package grpc

import (
	"errors"
	"net/http"
	"strings"

	"github.com/Allenxuxu/mMicro/api/resolver"
)

type Resolver struct{}

func (r *Resolver) Resolve(req *http.Request) (*resolver.Endpoint, error) {
	// /foo.Bar/Service
	if req.URL.Path == "/" {
		return nil, errors.New("unknown name")
	}
	// [foo.Bar, Service]
	parts := strings.Split(req.URL.Path[1:], "/")
	// [foo, Bar]
	name := strings.Split(parts[0], ".")
	// foo
	return &resolver.Endpoint{
		Name:   strings.Join(name[:len(name)-1], "."),
		Host:   req.Host,
		Method: req.Method,
		Path:   req.URL.Path,
	}, nil
}

func (r *Resolver) String() string {
	return "grpc"
}

func NewResolver(opts ...resolver.Option) resolver.Resolver {
	return &Resolver{}
}

package translatableerror

type UploadFailedError struct {
	Err error
}

func (UploadFailedError) Error() string {
	return "Uploading files have failed after a number of retriest due to: {{.Error}}"
}

func (e UploadFailedError) Translate(translate func(string, ...interface{}) string) string {
	var message string
	if err, ok := e.Err.(TranslatableError); ok {
		message = err.Translate(translate)
	} else if e.Err != nil {
		message = e.Err.Error()
	} else {
		message = translate("UNKNOWN REASON")
	}

	return translate(e.Error(), map[string]interface{}{
		"Error": message,
	})
}

